static void finish(void) {
    curs_set(1);
    wclear(stdscr);
    wrefresh(stdscr);
    endwin();
    if (current_screen) {
        delscreen(current_screen);
        current_screen = NULL;
    }
    if (tty_file) {
        fclose(tty_file);
        tty_file = NULL;
    }
    exit(0);
