                    wmove(stdscr, heads[c], c);
                    wattr_on(stdscr, COLOR_PAIR(2) | (bold == 2 ? A_BOLD : 0), NULL);
                    waddch(stdscr, ch);
                    wattr_off(stdscr, COLOR_PAIR(2) | (bold == 2 ? A_BOLD : 0), NULL);
                }
