                    wattr_on(stdscr, COLOR_PAIR(pair) | attr, NULL);
                    waddch(stdscr, ch);
                    wattr_off(stdscr, COLOR_PAIR(pair) | attr, NULL);
                }
                /* Erase tail */
                int tail = heads[c] - col_state[c].length;
