    cbreak();
    noecho();
    curs_set(0);
    leaveok(stdscr, TRUE);
    wtimeout(stdscr, 0);

    if (has_colors()) {
        start_color();
        use_default_colors();
        init_pair(1, color, -1);
        init_pair(2, COLOR_WHITE, -1);
        init_pair(3, COLOR_YELLOW, -1);
        init_pair(4, COLOR_RED, -1);
        init_pair(5, COLOR_BLUE, -1);
        init_pair(6, COLOR_MAGENTA, -1);
        init_pair(7, COLOR_CYAN, -1);
        init_pair(8, COLOR_BLACK, -1);
    }

