    int cols = COLS;
    int lines = LINES;
    if (cols < 1) cols = 80;
    if (lines < 1) lines = 24;

    column_t *col_state = calloc(cols, sizeof(column_t));
    if (!col_state) {
        endwin();
        fprintf(stderr, "CMatrix: malloc: out of memory!\n");
        exit(1);
    }

