    for (int c = 0; c < cols; c++) {
        col_state[c].length = rnd_range(3, lines / 2 + 1);
        col_state[c].spaces = rnd_range(0, lines);
        col_state[c].update = rnd_range(1, 9);
        col_state[c].color = (rainbow) ? (short)(1 + (rand() % 7)) : 1;
    }

