    int *cells = calloc(cols * lines, sizeof(int));
    if (!cells) {
        free(col_state);
        endwin();
        fprintf(stderr, "CMatrix: malloc: out of memory!\n");
        exit(1);
    }
    /* head position per column */
    int *heads = calloc(cols, sizeof(int));
    if (!heads) {
        free(col_state);
        free(cells);
        endwin();
        fprintf(stderr, "CMatrix: malloc: out of memory!\n");
        exit(1);
